from solution import merge_settings


def test_merge_settings_precedence_and_parsing():
    defaults = {
        "database": {"host": "localhost", "port": 5432},
        "debug": False,
        "workers": 2,
    }
    file_config = {"database": {"host": "db.local"}, "debug": True}
    env = {
        "APP__DATABASE__PORT": "6432",
        "APP__FEATURES": "search, billing,",
        "IGNORED": "yes",
    }

    merged = merge_settings(defaults, file_config, env)

    assert merged == {
        "database": {"host": "db.local", "port": 6432},
        "debug": True,
        "workers": 2,
        "features": ["search", "billing"],
    }
    assert defaults["database"]["host"] == "localhost"


def test_merge_settings_handles_bool_and_plain_string():
    merged = merge_settings({}, {}, {"APP__DEBUG": "false", "APP__NAME": "api"})
    assert merged == {"debug": False, "name": "api"}
